import{c as t,Q as r,j as a,m as o}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"Orrery","titleTemplate":"Documentation","description":"","frontmatter":{"layout":"home","title":"Orrery","titleTemplate":"Documentation","hero":{"name":"ORRERY","text":"Mission control for the curious.","tagline":"The orbital mechanics tools NASA uses to reach Mars, rebuilt for anyone who is curious. Real physics, real missions from Sputnik to Artemis II, in 14 languages. Beautiful, educational, self-hostable.","image":{"src":"/screenshots/hero-explore-3d.png","alt":"Orrery — solar system explorer"},"actions":[{"theme":"brand","text":"↗ Launch the app","link":"https://chipi.github.io/orrery/"},{"theme":"alt","text":"User guide","link":"/guides/user-guide"},{"theme":"alt","text":"Architecture","link":"/adr/TA"}]},"features":[{"icon":"🌌","title":"12 routes · real physics","details":"Solar System Explorer · Mission Configurator · Mission Arc · Mission Catalog · Earth / Moon / Mars surface maps · ISS + Tiangong explorers · Science encyclopedia · Spaceflight Fleet. Keplerian orbits, Lambert porkchops, vis-viva, Tsiolkovsky — the math behind real mission planning, presented so a curious person can understand by doing."},{"icon":"🛰️","title":"37 missions · 137 fleet entries","details":"Every flown crewed and robotic mission from Luna 9 to Chandrayaan-3, replayable with real flight parameters. Cross-referenced bidirectionally to a curated inventory of every machine used in spaceflight — launchers, capsules, stations, rovers, landers, orbiters, observatories, suits."},{"icon":"🌍","title":"14 locales · 100% UI parity","details":"English, Español, Français, Deutsch, Português (BR), Italiano, Nederlands, 中文, 日本語, 한국어, हिन्दी, العربية (RTL), Русский, Српски (Cyrillic). Browser locale auto-detected on first visit. No backend, no database, no personal data — a static PWA that works offline after first load."},{"icon":"🔬","title":"The Science Lens","details":"Toggle the lens icon and every 3D scene gets live physics annotations: gravity / velocity / centripetal arrows, sphere-of-influence rings, apsides and true anomaly, engine-off coast preview, conic-section family detection, microgravity axes, atmosphere shells, tidal-lock and ozone indicators. Casual users see clean scenes; curious users opt into the entire physics layer."},{"icon":"📚","title":"85 encyclopedia sections","details":"/science is a 10-tab encyclopedia covering every term, formula, and named law the simulator references — Orbits · Transfers · Propulsion · Mission Phases · Scales & Time · Porkchop · Space Stations · History · Observation · Life in Space. KaTeX-rendered math, 71 hand-coded SVG diagrams, Cmd-K search. Every \\"?\\" chip elsewhere in the app deep-links straight to the relevant chapter."},{"icon":"🛡️","title":"Honest provenance","details":"Every image, every outbound link, every paraphrased text fragment has a provenance row with source, license, and last-verified date. Agency-first sourcing prioritises operator-published material; failures are surfaced (Apollo 1, Challenger, Columbia, N1) with the same editorial weight as successes. /credits and /library make the bill of materials public."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),s={name:"index.md"};function i(n,e,c,l,d,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<div class="orrery-landing-body"><h2 id="the-repo" tabindex="-1">The repo <a class="header-anchor" href="#the-repo" aria-label="Permalink to &quot;The repo&quot;">​</a></h2><p>Source: <strong><a href="https://github.com/chipi/orrery" target="_blank" rel="noreferrer">github.com/chipi/orrery</a></strong></p><p>Live build: <strong><a href="https://chipi.github.io/orrery/" target="_blank" rel="noreferrer">chipi.github.io/orrery</a></strong> — every screen, fully offline-capable after first load. First-time visitors land on a 30-second orientation page; returning users skip past in one click via the nav.</p><h2 id="documentation-layout" tabindex="-1">Documentation layout <a class="header-anchor" href="#documentation-layout" aria-label="Permalink to &quot;Documentation layout&quot;">​</a></h2><p>This is the architecture and design documentation, not the user-facing help. Read order depends on what you are trying to do.</p><h3 id="start-here" tabindex="-1">Start here <a class="header-anchor" href="#start-here" aria-label="Permalink to &quot;Start here&quot;">​</a></h3><ul><li><strong><a href="/orrery/docs/guides/user-guide">User guide</a></strong> — read-this-first walk-through of the live app, screen by screen, with screenshots for all 11 primary nav routes plus the read-only provenance pages.</li><li><strong><a href="/orrery/docs/adr/TA">Architecture (TA.md)</a></strong> — single-page architecture map. Every route, subsystem, 3D scene, asset pipeline, contract, and constraint with the ADR that locked it.</li><li><strong><a href="/orrery/docs/guides/i18n-style-guide">Translator guide</a></strong> — binding glossary for translators, per ADR-033.</li></ul><h3 id="decision-history" tabindex="-1">Decision history <a class="header-anchor" href="#decision-history" aria-label="Permalink to &quot;Decision history&quot;">​</a></h3><ul><li><strong><a href="/orrery/docs/adr/">ADRs</a></strong> — 58 Architecture Decision Records, the load-bearing decisions of the project. Three of these (ADR-052/053/054) document the Spaceflight Fleet schema retrospectively.</li><li><strong><a href="/orrery/docs/rfc/">RFCs</a></strong> — 17 RFCs, the open architectural questions before they became ADRs. RFC-017 (Surface Hotspots) is currently open and gates v0.7.</li><li><strong><a href="/orrery/docs/prd/">PRDs</a></strong> — 14 Product Requirements Documents, the user-value arguments for every shipped feature.</li></ul><h3 id="concept-package" tabindex="-1">Concept package <a class="header-anchor" href="#concept-package" aria-label="Permalink to &quot;Concept package&quot;">​</a></h3><p>The founding narrative documents (00–05) — the original &quot;what is Orrery and why&quot; essays from prototyping. Worth reading for context on the design philosophy. Start with <code>02_Project_Concept.md</code>.</p><p>The six working HTML prototypes (P01–P06) are preserved as ground truth for the original physics and visual decisions.</p><h3 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h3><ul><li><strong>Provenance manifests</strong> (<code>docs/provenance/</code>) — image, link, and text-source audit logs.</li><li><strong>Research</strong> (<code>docs/research/</code>) — exploratory notes that haven&#39;t graduated to decisions yet.</li><li><strong><a href="/orrery/docs/TECH-BOM">Tech BOM</a></strong> — license audit of every npm dependency.</li></ul><h2 id="the-science-lens" tabindex="-1">The Science Lens <a class="header-anchor" href="#the-science-lens" aria-label="Permalink to &quot;The Science Lens&quot;">​</a></h2><p>The lens (top-nav icon) is what turns the simulator into a textbook.</p><p>When off, every 3D scene reads clean — Sun, planets, ships, trajectories. When on, the scene gains:</p><table tabindex="0"><thead><tr><th>Layer</th><th>What it shows</th></tr></thead><tbody><tr><td><strong>Sphere of influence</strong></td><td>translucent rings showing where each body&#39;s gravity dominates</td></tr><tr><td><strong>Gravity / velocity / centripetal arrows</strong></td><td>log-scaled so all are visible at once, with values printed at the tip</td></tr><tr><td><strong>Apsides</strong></td><td>perihelion / aphelion markers + a live <code>ν = 42°</code> true-anomaly callout</td></tr><tr><td><strong>Engine-off coast</strong></td><td>dotted projection of where the ship would drift if engines cut now</td></tr><tr><td><strong>Conic-section family</strong></td><td>names the current arc (circle / ellipse / parabola / hyperbola) live from specific orbital energy</td></tr><tr><td><strong>Microgravity axes</strong></td><td>zenith / nadir, prograde / retrograde, port / starboard on station scenes</td></tr><tr><td><strong>Atmosphere / tidal-lock / ozone</strong></td><td>atmospheric shells, tidal-lock hemisphere, ozone-hole zones</td></tr></tbody></table><p>The <strong>Flight Director banner</strong> on <code>/fly</code> narrates 5 physics phases (Departure · TLI · Cruise · Approach · Arrival), each phase deep-linking to the corresponding <code>/science</code> chapter. Eight lens layers wire into both <code>/fly</code> scenes — heliocentric for interplanetary, cislunar for Moon missions — so the same physics overlay reads correctly whether you&#39;re watching Curiosity coast to Mars or Apollo 17 swing around the far side of the Moon.</p><h2 id="how-it-s-built" tabindex="-1">How it&#39;s built <a class="header-anchor" href="#how-it-s-built" aria-label="Permalink to &quot;How it&#39;s built&quot;">​</a></h2><p><strong>Stack:</strong> SvelteKit + Three.js r128 + TypeScript (strict) + Vite. No backend, no database. Pure static SPA. PWA-installable, offline-capable after first paint. Hosted free on GitHub Pages.</p><p><strong>Data:</strong> All static JSON under <code>static/data/</code>. 33 ajv schemas validate every file fail-closed at build time. Locale overlays for 14 languages. Pre-computed Lambert porkchop grids for 9 destinations.</p><p><strong>Testing:</strong> ~1 000 unit tests (94.5 % statement coverage, 79.7 % branch, 89.2 % function, 96.3 % line — gated in CI). 57 Playwright e2e specs across desktop + mobile-chromium projects. Nightly e2e + weekly asset rebuild keep external drift in check.</p><p><strong>Honesty:</strong> Every image, every outbound LEARN link, every paraphrased text fragment carries a provenance row. Agency-first sourcing per ADR-046; no artist&#39;s impressions of flown vehicles; per-language native-source priority per ADR-051; symmetric-link validator catches bidirectional fleet-reference drift fail-closed per ADR-052.</p><p>For the full architecture map, decisions, and contracts, see <strong><a href="/orrery/docs/adr/TA">TA.md</a></strong>.</p></div>',1)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
